SELECT DISTINCT ?show ?showLabel WHERE {
  wd:Q684370 wdt:P161 ?show .
  ?show wdt:P31 wd:Q2724496 .
  ?show wdt:P577 ?firstAired .
  FILTER (YEAR(?firstAired) <= 2005)
  OPTIONAL { ?show wdt:P2079 ?endDate . }
  FILTER (IF(BOUND(?endDate), YEAR(?endDate) >= 2005, TRUE))
  ?show rdfs:label ?showLabel.
  FILTER (LANG(?showLabel) = "en")
}

